  async SubmitDecision() {
    if (this.DecisionForm.valid) {
      if (await this.alertService.SaveAlert()) {
        this.showLoader = true;
        this.http
          .post(
            this.env.API_URL + "api/LoanApplications/ApplicationDecisionInsert",
            {
              application_key:
                this.selectedLoanApplication.applicationKey.toString(),
              org_branch_code:
                this.selectedLoanApplication.orgBranchCode.toString(),
              client_code: this.selectedLoanApplication.clientCode.toString(),
              uuc_appl: this.selectedLoanApplication.uuc_appl.toString(),
              application_status:
                this.DecisionForm.value.application_status.toString(),
              com_dec_date: this.DecisionForm.value.com_dec_date.toString(),
              funder_code: this.DecisionForm.value.funder_code,
              loan_rej_code: this.DecisionForm.value.loan_rej_code,
              aprv_am: this.revisionVisitForm.value.requestedAmount.toString(),
              req_gp: this.selectedLoanApplication.req_gp.toString(),
              req_no: this.revisionVisitForm.value.req_no.toString(),
              app_charge_perc_type:
                this.selectedLoanApplication.app_charge_perc_type.toString(),
              app_charge_mem_perc_type:
                this.selectedLoanApplication.app_charge_mem_perc_type.toString(),
              funding_reference_id:
                this.DecisionForm.value.funding_reference_id,
            }
          )
          .subscribe({
            next: (data) => {
              this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
              this.showLoader = false;
            },
            error: (err) => {
              this.alertService.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    } else {
      this.alertService.showAlertError("برجاء ادخال بيانات بشكل صحيح", false);
    }
  }

