  GetFundingReference($event) {
    if ($event.detail.value != "") {
      this.showLoader = true;
      this.http
        .post(this.env.API_URL + "api/LoanApplications/GetFundingReference", {
          org_code: this.org_code,
          funder_code: $event.detail.value,
        })
        .subscribe({
          next: (data) => {
            console.log(data);
            this.FundingRef = data["fundingRefs"];
            this.iscore_external_funding = data["iscore_external_funding"];
            if (this.iscore_external_funding == "1") {
              this.isIscore_external_funding = true;
            } else {
              this.isIscore_external_funding = false;
              this.DecisionForm.patchValue({ funding_reference_id: null });
            }
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err);
            this.showLoader = false;
          },
        });
    }
  }

  GetClientImages() {
    this.showLoader = true;
    this.http
      .post(this.env.API_URL + "api/Documents/GetClientImages", {
        client_key: this.selectedLoanApplication.clientKey.toString(),
        application_key:
          this.selectedLoanApplication.applicationKey != null
            ? this.selectedLoanApplication.applicationKey.toString()
            : null,
        doc_type_code: "-990",
      })
      .subscribe({
        next: (data) => {
          this.ClientDocuments = data;
          this.allDocs = this.getDistinctValues(
            this.ClientDocuments,
            "doc_image"
          );
          if (this.allDocs.length != 0) {
            this.hasDocs = true;
          } else {
            this.hasDocs = false;
          }
          this.showLoader = false;
        },
        error: (err) => {
          this.alertService.showAlertError(err.error, false);
          this.showLoader = false;
        },
      });
  }

  getDistinctValues(data: any[], distinct_name: string): any[] {
    const values = data.map((item: any) => item[distinct_name]);
    const distinctValues = values.filter(
      (value: any, index: number, array: any[]) =>
        value != null && array.indexOf(value) === index
    );
    return distinctValues;
  }

  async presentToast(header: string, message: string): Promise<void> {
    let toast = await this.toastController.create({
      header: header,
      message: message,
      cssClass: "toast-primary",
      duration: 2000,
      position: "bottom",
    });

    await toast.present();
  }

  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }

  showCurrentDocuments() {
    this.displayDocuments = !this.displayDocuments;
  }
